/// Get the binary screenshots from the form trigger
const formNode = $('On form submission').first();

// Build new items with binary attached
const items = $input.all();

for (const item of items) {
  // Initialize binary object if not exists
  item.binary = item.binary || {};

  // Copy "Your App Screenshots" binary from form trigger
  if (formNode.binary && formNode.binary.Your_App_Screenshots) {
    item.binary.Your_App_Screenshots = formNode.binary.Your_App_Screenshots;
  }

  // Copy "Competitor App Screenshots" binary from form trigger
  if (formNode.binary && formNode.binary.Competitor_App_Screenshots) {
    item.binary.Competitor_App_Screenshots = formNode.binary.Competitor_App_Screenshots;
  }
}

return items;
